/**
 * 🔴 ADMIN QUERIES - Next.js 14
 * 
 * Estrutura Real do Banco (Schema: public)
 * 
 * Tabelas Descobertas:
 * - profiles: id, email, nome, telefone, avatar_url, data_nascimento, tipo_usuario, ativo, created_at, updated_at
 * - user_roles: id, user_id, role_type, is_active, created_at, updated_at
 * - aulas: id, titulo, descricao, professor_id, data, duracao_minutos, status, sala, instrumento, nivel, max_alunos, ativo, created_at, updated_at
 * 
 * Observações:
 * - profiles.tipo_usuario: 'admin' | 'professor' | 'aluno'
 * - user_roles.role_type: 'admin' | 'professor' | 'aluno'
 * - aulas.status: 'agendada' | 'em_andamento' | 'concluida' | 'cancelada'
 * - aulas.nivel: 'iniciante' | 'intermediario' | 'avancado'
 * - Relacionamentos: profiles.id → auth.users.id, user_roles.user_id → auth.users.id, aulas.professor_id → auth.users.id
 */

import { supabase } from '../client'

/**
 * Dashboard Stats - Usando profiles.tipo_usuario (estrutura real)
 */
export async function getAdminDashboardStats() {
  try {
    // Total de alunos ativos (via profiles.tipo_usuario)
    const { count: totalAlunos } = await supabase
      .from('profiles')
      .select('*', { count: 'exact', head: true })
      .eq('tipo_usuario', 'aluno')
      .eq('ativo', true)

    // Total de professores ativos (via profiles.tipo_usuario)
    const { count: totalProfessores } = await supabase
      .from('profiles')
      .select('*', { count: 'exact', head: true })
      .eq('tipo_usuario', 'professor')
      .eq('ativo', true)

    // Total de aulas ativas (excluindo canceladas)
    const { count: totalAulas } = await supabase
      .from('aulas')
      .select('*', { count: 'exact', head: true })
      .eq('ativo', true)
      .neq('status', 'cancelada')

    // Aulas hoje
    const hoje = new Date().toISOString().split('T')[0]
    const { count: aulasHoje } = await supabase
      .from('aulas')
      .select('*', { count: 'exact', head: true })
      .eq('ativo', true)
      .gte('data', `${hoje}T00:00:00`)
      .lt('data', `${hoje}T23:59:59`)

    return {
      totalAlunos: totalAlunos || 0,
      totalProfessores: totalProfessores || 0,
      totalAulas: totalAulas || 0,
      aulasHoje: aulasHoje || 0,
    }
  } catch (error) {
    console.error('Erro ao buscar stats do dashboard:', error)
    return {
      totalAlunos: 0,
      totalProfessores: 0,
      totalAulas: 0,
      aulasHoje: 0,
    }
  }
}

/**
 * Lista de Professores - Usando profiles.tipo_usuario
 */
export async function getProfessores(filters?: {
  search?: string
  ativo?: boolean
  limit?: number
  offset?: number
}) {
  try {
    let query = supabase
      .from('profiles')
      .select('*', { count: 'exact' })
      .eq('tipo_usuario', 'professor')

    if (filters?.ativo !== undefined) {
      query = query.eq('ativo', filters.ativo)
    }

    if (filters?.search) {
      query = query.or(`nome.ilike.%${filters.search}%,email.ilike.%${filters.search}%`)
    }

    query = query.order('nome', { ascending: true })

    if (filters?.limit) {
      query = query.limit(filters.limit)
    }

    if (filters?.offset) {
      query = query.range(filters.offset, filters.offset + (filters.limit || 10) - 1)
    }

    const { data, error, count } = await query

    if (error) throw error

    return { data, count: count || 0 }
  } catch (error) {
    console.error('Erro ao buscar professores:', error)
    return { data: [], count: 0 }
  }
}

